CustomFunction.Calculation:
// Executes the query and returns results as a JSON array of objects.
// keys is a ¶-delimited list of property names for each selected column,
// in the same order as the SELECT list. The natural source is List():
//   QueryGetResultsAsJson_cf ( _query ; List ( "id" ; "name" ; "status" ) )
// Returns "[]" when the query produces no rows or an error.
Let
(
[
_keyCount = ValueCount ( keys ) ;
_rawResult = QueryGet_cf ( query ; Char ( 28 ) ; "¶" ) ;
_rowCount = If ( IsEmpty ( _rawResult ) ; 0 ; ValueCount ( _rawResult ) )
];
If ( _rowCount = 0 ;
	"[]" ;
// ELSE
	QueryBuildJsonRows_cf ( "[]" ; _rawResult ; _rowCount ; keys ; _keyCount ; 1 )
)
)
